634: /**
635:  * FilterManager manages decoding a request through a series of decoding filter and the encoding
636:  * of the resulting response.
637:  */
638: class FilterManager : public ScopeTrackedObject,
639:                       public FilterChainManager,
640:                       Logger::Loggable<Logger::Id::http> {
641: public:
642:   FilterManager(FilterManagerCallbacks& filter_manager_callbacks, Event::Dispatcher& dispatcher,
643:                 OptRef<const Network::Connection> connection, uint64_t stream_id,
644:                 Buffer::BufferMemoryAccountSharedPtr account, bool proxy_100_continue,
645:                 uint32_t buffer_limit, const FilterChainFactory& filter_chain_factory)
646:       : filter_manager_callbacks_(filter_manager_callbacks), dispatcher_(dispatcher),
647:         connection_(connection), stream_id_(stream_id), account_(std::move(account)),
648:         proxy_100_continue_(proxy_100_continue), buffer_limit_(buffer_limit),
649:         filter_chain_factory_(filter_chain_factory),
650:         no_downgrade_to_canonical_name_(Runtime::runtimeFeatureEnabled(
651:             "envoy.reloadable_features.no_downgrade_to_canonical_name")) {}
652:   ~FilterManager() override {
653:     ASSERT(state_.destroyed_);
654:     ASSERT(state_.filter_call_state_ == 0);
655:   }
656: 
657:   // ScopeTrackedObject
658:   void dumpState(std::ostream& os, int indent_level = 0) const override {
659:     const char* spaces = spacesForLevel(indent_level);
660:     os << spaces << "FilterManager " << this << DUMP_MEMBER(state_.has_1xx_headers_) << "\n";
661: 
662:     DUMP_DETAILS(filter_manager_callbacks_.requestHeaders());
663:     DUMP_DETAILS(filter_manager_callbacks_.requestTrailers());
664:     DUMP_DETAILS(filter_manager_callbacks_.responseHeaders());
665:     DUMP_DETAILS(filter_manager_callbacks_.responseTrailers());
666:     DUMP_DETAILS(&streamInfo());
667:   }
668: 
669:   void addAccessLogHandler(AccessLog::InstanceSharedPtr handler) {
670:     access_log_handlers_.push_back(std::move(handler));
671:   }
672:   void addStreamDecoderFilter(ActiveStreamDecoderFilterPtr filter) {
673:     // Note: configured decoder filters are appended to decoder_filters_.
674:     // This means that if filters are configured in the following order (assume all three filters
675:     // are both decoder/encoder filters):
676:     //   http_filters:
677:     //     - A
678:     //     - B
679:     //     - C
680:     // The decoder filter chain will iterate through filters A, B, C.
681:     LinkedList::moveIntoListBack(std::move(filter), decoder_filters_);
682:   }
683:   void addStreamEncoderFilter(ActiveStreamEncoderFilterPtr filter) {
684:     // Note: configured encoder filters are prepended to encoder_filters_.
685:     // This means that if filters are configured in the following order (assume all three filters
686:     // are both decoder/encoder filters):
687:     //   http_filters:
688:     //     - A
689:     //     - B
690:     //     - C
691:     // The encoder filter chain will iterate through filters C, B, A.
692:     LinkedList::moveIntoList(std::move(filter), encoder_filters_);
693:   }
694:   void addStreamFilterBase(StreamFilterBase* filter) { filters_.push_back(filter); }
695: 
696:   // FilterChainManager
697:   void applyFilterFactoryCb(FilterContext context, FilterFactoryCb& factory) override;
698: 
699:   void log(AccessLog::AccessLogType access_log_type) {
700:     const Formatter::HttpFormatterContext log_context{
701:         filter_manager_callbacks_.requestHeaders().ptr(),
702:         filter_manager_callbacks_.responseHeaders().ptr(),
703:         filter_manager_callbacks_.responseTrailers().ptr(),
704:         {},
705:         access_log_type,
706:         &filter_manager_callbacks_.activeSpan()};
707: 
708:     for (const auto& log_handler : access_log_handlers_) {
709:       log_handler->log(log_context, streamInfo());
710:     }
711:   }
712: 
713:   std::list<AccessLog::InstanceSharedPtr> accessLogHandlers() { return access_log_handlers_; }
714: 
715:   void onStreamComplete() {
716:     for (auto& filter : decoder_filters_) {
717:       filter->handle_->onStreamComplete();
718:     }
719: 
720:     for (auto& filter : encoder_filters_) {
721:       // Do not call onStreamComplete twice for dual registered filters.
722:       if (!filter->is_encoder_decoder_filter_) {
723:         filter->handle_->onStreamComplete();
724:       }
725:     }
726:   }
727: 
728:   void destroyFilters() {
729:     state_.destroyed_ = true;
730: 
731:     for (auto& filter : decoder_filters_) {
732:       filter->handle_->onDestroy();
733:     }
734: 
735:     for (auto& filter : encoder_filters_) {
736:       // Do not call on destroy twice for dual registered filters.
737:       if (!filter->is_encoder_decoder_filter_) {
738:         filter->handle_->onDestroy();
739:       }
740:     }
741:   }
742: 
743:   /**
744:    * Decodes the provided headers starting at the first filter in the chain.
745:    * @param headers the headers to decode.
746:    * @param end_stream whether the request is header only.
747:    */
748:   void decodeHeaders(RequestHeaderMap& headers, bool end_stream) {
749:     state_.remote_decode_complete_ = end_stream;
750:     decodeHeaders(nullptr, headers, end_stream);
751:   }
752: 
753:   /**
754:    * Decodes the provided data starting at the first filter in the chain.
755:    * @param data the data to decode.
756:    * @param end_stream whether this data is the end of the request.
757:    */
758:   void decodeData(Buffer::Instance& data, bool end_stream) {
759:     state_.remote_decode_complete_ = end_stream;
760:     decodeData(nullptr, data, end_stream, FilterIterationStartState::CanStartFromCurrent);
761:   }
762: 
763:   /**
764:    * Decodes the provided trailers starting at the first filter in the chain.
765:    * @param trailers the trailers to decode.
766:    */
767:   void decodeTrailers(RequestTrailerMap& trailers) {
768:     state_.remote_decode_complete_ = true;
769:     decodeTrailers(nullptr, trailers);
770:   }
771: 
772:   /**
773:    * Decodes the provided metadata starting at the first filter in the chain.
774:    * @param metadata_map the metadata to decode.
775:    */
776:   void decodeMetadata(MetadataMap& metadata_map) { decodeMetadata(nullptr, metadata_map); }
777: 
778:   void disarmRequestTimeout();
779: 
780:   /**
781:    * If end_stream is true, marks encoding as complete. This is a noop if end_stream is false.
782:    * @param end_stream whether encoding is complete.
783:    */
784:   void maybeEndEncode(bool end_stream);
785: 
786:   virtual void sendLocalReply(Code code, absl::string_view body,
787:                               const std::function<void(ResponseHeaderMap& headers)>& modify_headers,
788:                               const absl::optional<Grpc::Status::GrpcStatus> grpc_status,
789:                               absl::string_view details) PURE;
790: 
791:   void resetStream(StreamResetReason reason, absl::string_view transport_failure_reason);
792: 
793:   /**
794:    * Executes a prepared, but not yet propagated, local reply.
795:    * Prepared local replies can occur in the decoder filter chain iteration.
796:    */
797:   virtual void executeLocalReplyIfPrepared() PURE;
798: 
799:   // Possibly increases buffer_limit_ to the value of limit.
800:   void setBufferLimit(uint32_t limit);
